update dda_programmes
set contenu = jsonb_set(
  contenu,
  '{sections}',
  (
    select jsonb_agg(
      case when m.val is not null
      then jsonb_set(elem, '{questions}', (elem->'questions') || m.val)
      else elem end
    )
    from jsonb_array_elements(contenu->'sections') elem
    left join jsonb_each($map${"evaluation_b": [{"q": "Quel partenaire est le porteur principal des contrats Cyber+RCP distribués par S@FE ?", "opts": ["Hiscox", "AMI3F", "Wakam"], "correct": 0}, {"q": "La garantie « frais de gestion de crise » d'un contrat Cyber couvre notamment :", "opts": ["L'intervention d'experts (forensic, communication de crise, conseil juridique)", "Le remplacement du matériel informatique ancien", "La formation du personnel en bureautique"], "correct": 0}, {"q": "La garantie rançongiciel d'un contrat Cyber :", "opts": ["Est identique dans tous les contrats du marché", "Doit être vérifiée précisément contrat par contrat", "N'existe dans aucun contrat Cyber"], "correct": 1}, {"q": "La RC Professionnelle est-elle obligatoire pour toutes les activités ?", "opts": ["Oui, pour toutes sans exception", "Non, cela dépend du secteur (professions réglementées notamment)", "Non, elle n'est jamais obligatoire"], "correct": 1}, {"q": "La présomption de responsabilité de la loi Spinetta signifie que le maître d'ouvrage :", "opts": ["Doit prouver une faute du constructeur", "N'a pas à prouver une faute du constructeur", "Ne peut jamais être indemnisé"], "correct": 1}, {"q": "L'assurance dommages-ouvrage permet au maître d'ouvrage d'être indemnisé :", "opts": ["Uniquement après une décision de justice définitive", "Rapidement, sans attendre une décision de justice sur les responsabilités", "Jamais avant 10 ans"], "correct": 1}, {"q": "Dans une flotte nominative, le bonus-malus peut être suivi :", "opts": ["Individuellement par conducteur identifié", "Uniquement de façon globale sans distinction", "Il n'existe pas de bonus-malus en flotte nominative"], "correct": 0}, {"q": "Un véhicule de fonction, par rapport à un véhicule de service, modifie l'exposition au risque car :", "opts": ["Il est utilisé uniquement au bureau", "Il est utilisé aussi à titre privé, avec un kilométrage souvent plus élevé", "Il ne roule jamais le week-end"], "correct": 1}, {"q": "Pour une flotte incluant des livraisons transfrontalières, quel élément du contrat doit être réexaminé sans attendre le renouvellement ?", "opts": ["La couleur des véhicules", "La zone géographique de couverture", "Le nombre de sièges par véhicule"], "correct": 1}, {"q": "La table `prospects` de SafeCRM se distingue de `establishments` par :", "opts": ["Une traçabilité renforcée (audit trail) et une rétention encadrée de 3 ans", "L'absence totale de données", "Une rétention illimitée sans contrôle"], "correct": 0}, {"q": "Les sources de prospection B2B légitimes incluent notamment :", "opts": ["Les bases de données publiques et le réseau professionnel", "Uniquement les réseaux sociaux personnels", "L'achat de fichiers non vérifiés"], "correct": 0}, {"q": "Un code NAF de BTP orientera plutôt le conseiller vers un questionnement :", "opts": ["Cyber", "Décennale", "Flotte uniquement"], "correct": 1}, {"q": "Face à un dirigeant, les questions de découverte portent davantage sur :", "opts": ["La situation familiale et le patrimoine personnel", "L'exposition de l'activité de l'entreprise", "Les loisirs du dirigeant"], "correct": 1}, {"q": "Malgré l'auto-complétion du SIRET, quel élément Émilie doit-elle systématiquement recueillir à l'oral ?", "opts": ["La forme juridique de l'entreprise", "La sinistralité passée du client", "Le code NAF"], "correct": 1}, {"q": "Dans la méthode AIDA appliquée à un dirigeant, l'accroche (Attention) doit reposer sur :", "opts": ["Une généralité sur l'assurance", "Un risque concret et sectoriel récent", "Le tarif le plus bas du marché"], "correct": 1}, {"q": "Face à l'objection « mon assurance actuelle couvre déjà ça » sur le risque cyber, la meilleure réponse est :", "opts": ["Affirmer que c'est faux sans vérification", "Vérifier précisément le contrat existant du client", "Changer immédiatement de sujet"], "correct": 1}, {"q": "L'objection « c'est trop cher pour mon budget de TPE » peut être traitée en reformulant :", "opts": ["Le coût en prime mensuelle plutôt qu'annuelle", "Le nom de l'assureur partenaire", "La durée du contrat uniquement"], "correct": 0}, {"q": "Quand le client demande « pourquoi je finis sur un autre site pour signer ? », la meilleure réponse repose sur :", "opts": ["Une distinction claire entre rôle de conseil (S@FE) et rôle de porteur de risque (assureur)", "Le silence, pour éviter le sujet", "Une remise en cause du choix du client"], "correct": 0}, {"q": "Le statut `pending_manual_entry` dans SafeCRM signale :", "opts": ["Un dossier finalisé avec succès", "Un dossier en attente de ressaisie manuelle par Émilie", "Un dossier annulé définitivement"], "correct": 1}, {"q": "Un dossier resté trop longtemps en `redirected_to_partner` ou `pending_manual_entry` doit faire l'objet :", "opts": ["D'aucune action, le client recontactera de lui-même", "D'une relance", "D'une suppression immédiate du dossier"], "correct": 1}]}$map$::jsonb) m(key, val) on m.key = elem->>'id'
  )
)
where id = '005e7570-dd00-41cd-952b-5b8d5f158090';
